import React, { useEffect, useState } from 'react';
import { View, Text, ScrollView, StyleSheet, ActivityIndicator, TouchableOpacity } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import MaterialCommunityIcons from '@expo/vector-icons/MaterialCommunityIcons';
import axios from 'axios';
import AsyncStorage from '@react-native-async-storage/async-storage';

const GROQ_API_KEY = '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';

export default function App() {
  const [weather, setWeather] = useState<any>(null);
  const [description, setDescription] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [location, setLocation] = useState('Київ');

  useEffect(() => {
    fetchWeather();
  }, []);

  const fetchWeather = async () => {
    try {
      setLoading(true);

      // Fetch weather from Open-Meteo
      const response = await axios.get('https://api.open-meteo.com/v1/forecast', {
        params: {
          latitude: 50.4501,
          longitude: 30.5234,
          current: 'temperature_2m,relative_humidity_2m,apparent_temperature,precipitation,weather_code,wind_speed_10m,pressure_msl,uv_index,cloud_cover',
          timezone: 'auto',
        },
      });

      const current = response.data.current;
      setWeather({
        temperature: Math.round(current.temperature_2m),
        feelsLike: Math.round(current.apparent_temperature),
        humidity: current.relative_humidity_2m,
        windSpeed: Math.round(current.wind_speed_10m),
        pressure: current.pressure_msl,
        uvIndex: current.uv_index,
        cloudCover: current.cloud_cover,
      });

      // Get description from Groq
      const groqResponse = await axios.post(
        'https://api.groq.com/openai/v1/chat/completions',
        {
          model: 'llama-3.3-70b-versatile',
          messages: [
            {
              role: 'user',
              content: `Ви - метеоролог. Опишіть погоду в ${location} українською мовою на основі цих даних:

Температура: ${current.temperature_2m}°C (відчувається як ${current.apparent_temperature}°C)
Вологість: ${current.relative_humidity_2m}%
Вітер: ${Math.round(current.wind_speed_10m)} км/год
Тиск: ${current.pressure_msl} гПа
УФ індекс: ${current.uv_index}
Хмарність: ${current.cloud_cover}%

Дайте короткий, інформативний опис (2-3 речення).`,
            },
          ],
          temperature: 0.7,
          max_tokens: 300,
        },
        {
          headers: {
            Authorization: `Bearer ${GROQ_API_KEY}`,
            'Content-Type': 'application/json',
          },
        }
      );

      const desc = groqResponse.data.choices[0].message.content;
      setDescription(desc);
    } catch (error) {
      console.error('Error:', error);
      setDescription('Не вдалося отримати опис погоди');
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.centerContent}>
          <ActivityIndicator size="large" color="#1E88E5" />
          <Text style={styles.loadingText}>Завантаження погоди...</Text>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView style={styles.scrollView}>
        <View style={styles.header}>
          <Text style={styles.title}>WeatherPro</Text>
          <Text style={styles.location}>{location}</Text>
        </View>

        {weather && (
          <>
            <View style={styles.mainCard}>
              <MaterialCommunityIcons name="cloud" size={80} color="#1E88E5" />
              <Text style={styles.temperature}>{weather.temperature}°C</Text>
              <Text style={styles.feelsLike}>Відчувається як {weather.feelsLike}°C</Text>
            </View>

            <View style={styles.detailsCard}>
              <View style={styles.detailRow}>
                <MaterialCommunityIcons name="water-percent" size={24} color="#1E88E5" />
                <Text style={styles.detailLabel}>Вологість</Text>
                <Text style={styles.detailValue}>{weather.humidity}%</Text>
              </View>

              <View style={styles.detailRow}>
                <MaterialCommunityIcons name="weather-windy" size={24} color="#1E88E5" />
                <Text style={styles.detailLabel}>Вітер</Text>
                <Text style={styles.detailValue}>{weather.windSpeed} км/год</Text>
              </View>

              <View style={styles.detailRow}>
                <MaterialCommunityIcons name="gauge" size={24} color="#1E88E5" />
                <Text style={styles.detailLabel}>Тиск</Text>
                <Text style={styles.detailValue}>{weather.pressure} гПа</Text>
              </View>

              <View style={styles.detailRow}>
                <MaterialCommunityIcons name="sun-wireless-outline" size={24} color="#FFA500" />
                <Text style={styles.detailLabel}>УФ індекс</Text>
                <Text style={styles.detailValue}>{weather.uvIndex}</Text>
              </View>
            </View>

            <View style={styles.descriptionCard}>
              <View style={styles.descriptionHeader}>
                <MaterialCommunityIcons name="cloud-info" size={24} color="#1E88E5" />
                <Text style={styles.descriptionTitle}>Опис погоди</Text>
              </View>
              <Text style={styles.descriptionText}>{description}</Text>
            </View>
          </>
        )}

        <TouchableOpacity style={styles.refreshButton} onPress={fetchWeather}>
          <MaterialCommunityIcons name="refresh" size={24} color="white" />
          <Text style={styles.refreshButtonText}>Оновити</Text>
        </TouchableOpacity>
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F5F5F5',
  },
  scrollView: {
    flex: 1,
  },
  centerContent: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  loadingText: {
    marginTop: 16,
    fontSize: 16,
    color: '#666',
  },
  header: {
    paddingHorizontal: 16,
    paddingVertical: 12,
  },
  title: {
    fontSize: 32,
    fontWeight: 'bold',
    color: '#212121',
  },
  location: {
    fontSize: 16,
