    borderRadius: 16,
    alignItems: 'center',
    elevation: 4,
  },
  temperature: {
    fontSize: 64,
    fontWeight: 'bold',
    color: '#1E88E5',
    marginTop: 12,
  },
  feelsLike: {
    fontSize: 14,
    color: '#999',
    marginTop: 8,
  },
  detailsCard: {
    marginHorizontal: 16,
    marginVertical: 12,
    padding: 16,
    backgroundColor: '#FFFFFF',
    borderRadius: 12,
    elevation: 2,
  },
  detailRow: {
    flexDirection: 'row',
    alignItems: 'center',
    paddingVertical: 12,
    borderBottomWidth: 1,
    borderBottomColor: '#EEEEEE',
  },
  detailLabel: {
    flex: 1,
    fontSize: 14,
    color: '#666',
    marginLeft: 12,
  },
  detailValue: {
    fontSize: 14,
    fontWeight: '600',
    color: '#212121',
  },
  descriptionCard: {
    marginHorizontal: 16,
    marginVertical: 12,
    padding: 16,
    backgroundColor: '#E3F2FD',
    borderRadius: 12,
    borderLeftWidth: 4,
    borderLeftColor: '#1E88E5',
  },
  descriptionHeader: {
    flexDirection: 'row',
    alignItems: 'center',
    marginBottom: 12,
  },
  descriptionTitle: {
    fontSize: 16,
    fontWeight: '600',
    color: '#1E88E5',
    marginLeft: 8,
  },
  descriptionText: {
    fontSize: 14,
    color: '#1565C0',
    lineHeight: 20,
    fontWeight: '500',
  },
  refreshButton: {
    marginHorizontal: 16,
    marginVertical: 20,
    paddingVertical: 14,
    paddingHorizontal: 24,
    backgroundColor: '#1E88E5',
    borderRadius: 8,
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
  },
  refreshButtonText: {
    fontSize: 16,
    fontWeight: '600',
    color: 'white',
    marginLeft: 8,
  },
});
